SELECT AVG(stem_mass_dry) AS average_stem_mass_dry
FROM plant_growth
WHERE health_status = 'Healthy';

SELECT chamber_name
FROM chambers
WHERE capacity > 50;

SELECT chamber_name, capacity
FROM chambers
ORDER BY capacity DESC;

SELECT AVG(wf_value) AS average_wf_value
FROM wf
WHERE chamber_id = 1 AND measurement_date = '2023-01-01';

SELECT COUNT(*) AS chamber_count
FROM chambers
WHERE location = 'Greenhouse 1';

SELECT COUNT(experiment_id) AS experiment_count
FROM chamber_experiments
WHERE chamber_id = 1;

SELECT AVG(wbr_value) AS average_wbr, MAX(wbr_value) AS max_wbr
FROM wbr
WHERE chamber_id = 1;
